/**
 * Calculates (base^exp) % mod efficiently using binary exponentiation.
 * @param {bigint} base 
 * @param {bigint} exp 
 * @param {bigint} mod 
 * @returns {bigint}
 */
function power(base, exp, mod) {
    let res = 1n;
    base %= mod;
    while (exp > 0n) {
        if (exp % 2n === 1n) {
            res = (res * base) % mod;
        }
        base = (base * base) % mod;
        exp /= 2n;
    }
    return res;
}

/**
 * Solves the problem by sorting segments greedily and calculating the resulting value modulo 10^9 + 7.
 * @param {number[]} nums1 
 * @param {number[]} nums0 
 * @returns {number}
 */
function solve(nums1, nums0) {
    const MOD = 1000000007n;

    // 1. Prepare segments structure for sorting
    // We store [W, Z] where W = nums1[i], Z = nums0[i]
    const segments = [];
    for (let i = 0; i < nums1.length; i++) {
        segments.push({ w: nums1[i], z: nums0[i] });
    }

    // 2. Define the custom comparator
    // We prefer segment A over segment B if A concatenated with B > B concatenated with A lexicographically.
    // This translates to sorting primarily by W descending, and secondarily by Z ascending.
    segments.sort((a, b) => {
        // Compare W (nums1) descending
        if (a.w !== b.w) {
            return b.w - a.w; // Larger W comes first
        }
        // W is equal, compare Z (nums0) ascending
        return a.z - b.z; // Smaller Z comes first
    });

    // 3. Calculate the total value iteratively (backward iteration)
    let totalValue = 0n;
    let powerOfTwoMultiplier = 1n; // P = 2^(length of suffix)

    // Iterate backwards through the sorted segments (S_n, S_{n-1}, ..., S_1)
    for (let i = segments.length - 1; i >= 0; i--) {
        const seg = segments[i];
        const W = BigInt(seg.w);
        const Z = BigInt(seg.z);

        // Calculate V_i: The numerical value of the segment 1^W 0^Z
        // V_i = 2^Z * (2^W - 1) mod MOD

        // 2^W - 1 mod MOD
        let term1 = (power(2n, W, MOD) - 1n + MOD) % MOD;

        // 2^Z mod MOD
        let term2 = power(2n, Z, MOD);

        // V_i = term1 * term2 mod MOD
        let Vi = (term1 * term2) % MOD;

        // V = (V + V_i * P) mod MOD
        let contribution = (Vi * powerOfTwoMultiplier) % MOD;
        totalValue = (totalValue + contribution) % MOD;

        // Update P: P = P * 2^(W+Z) mod MOD
        const L = W + Z;
        powerOfTwoMultiplier = (powerOfTwoMultiplier * power(2n, L, MOD)) % MOD;
    }

    return Number(totalValue);
}

